import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface TopDeal {
  item: string;
  discountPercent: number;
  expiry: string;
}

interface DealsData {
  topDeals: TopDeal[];
}

export default function Widget() {
  const dealsData = response.data as DealsData;
  const { topDeals } = dealsData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 400, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Typography variant="h6" fontWeight={600} sx={{ color: '#FF5722' }}>
            Top Deals
          </Typography>
          <Stack spacing={1.5}>
            {topDeals.map((deal) => (
              <Box key={deal.item}>
                <Stack direction="row" justifyContent="space-between" alignItems="center">
                  <Typography variant="body2" fontWeight={500} sx={{ color: '#374151' }}>
                    {deal.item}
                  </Typography>
                  <Chip
                    label={`${deal.discountPercent}% off`}
                    sx={{ bgcolor: '#FFC107', color: '#FFFFFF', fontWeight: 600 }}
                  />
                </Stack>
                <Typography variant="caption" color="text.secondary" sx={{ mt: 0.5 }}>
                  Expires on: {new Date(deal.expiry).toLocaleDateString()}
                </Typography>
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
